window.addEventListener('load', function () {
(window.requestIdleCallback || function(cb){ setTimeout(cb, 300); })(function () {
const heroSection = document.getElementById('heroSection');
if (heroSection && window.innerWidth <= 575) {
const mobileBg = heroSection.dataset.bgMobile;
const heroBgImg = heroSection.querySelector('.hero-bg-img');
if (mobileBg && heroBgImg) heroBgImg.src = mobileBg;
}
const video = document.getElementById('mainVideo');
if (video && window.HOME_ASSETS && HOME_ASSETS.fullVideo) {
video.style.visibility = 'hidden';
const source = document.createElement('source');
source.src = HOME_ASSETS.fullVideo;
source.type = 'video/mp4';
video.appendChild(source);
video.load();
video.addEventListener('canplaythrough', () => {
video.style.visibility = 'visible';
video.play().catch(() => {});
}, { once: true });
}
});
const accordions = document.querySelectorAll('.accordion');
accordions.forEach(accordion => {
const btn = accordion.querySelector('button');
if (!btn) return;
btn.addEventListener('click', () => {
const body = accordion.querySelector('.accordion-body');
const expandedHeight = body ? body.scrollHeight + 'px' : null;
requestAnimationFrame(() => {
accordions.forEach(item => {
if (item !== accordion) {
item.classList.remove('active');
const b = item.querySelector('.accordion-body');
if (b) b.style.maxHeight = null;
}
});
accordion.classList.toggle('active');
if (body) {
body.style.maxHeight = accordion.classList.contains('active') ? expandedHeight : null;
}
});
});
});
const serviceContent = document.querySelector('.services-content');
const serviceItems = document.querySelectorAll('.service-item');
const imageWrapper = document.querySelector('.image-wraper img');
const serviceImages = window.HOME_ASSETS ? HOME_ASSETS.serviceImages : [];
let scrollPending = false;
function handleScroll() {
if (scrollPending) return;
scrollPending = true;
requestAnimationFrame(() => {
const rect = serviceContent
? serviceContent.getBoundingClientRect()
: { top: Infinity, bottom: -Infinity, height: 0 };
const wh = window.innerHeight;
const trigger = wh * 0.6;
const items = Array.from(serviceItems);
const rects = items.map(i => i.getBoundingClientRect());
const activeStates = rects.map(r => r.top < trigger && r.bottom > 0);
const activeIndex = activeStates.lastIndexOf(true);
const scrolledPx = Math.min(trigger - rect.top, rect.height);
const scrollH = rect.top < trigger && rect.bottom > 0 ? `${scrolledPx}px` : '0px';
items.forEach((item, i) => item.classList.toggle('active', activeStates[i]));
if (activeIndex !== -1 && imageWrapper && serviceImages[activeIndex] &&
!imageWrapper.src.includes(serviceImages[activeIndex])) {
imageWrapper.src = serviceImages[activeIndex];
}
if (serviceContent) serviceContent.style.setProperty('--scroll-height', scrollH);
scrollPending = false;
});
}
window.addEventListener('scroll', handleScroll, { passive: true });
handleScroll();
if (window.matchMedia('(pointer: fine)').matches) {
const section = document.querySelector('.videos-section');
const floatingBtn = document.querySelector('.floating-btn');
let targetX = 0, targetY = 0, currentX = 0, currentY = 0;
let isInside = false;
let sectionRect = section ? section.getBoundingClientRect() : { left: 0, top: 0 };
let btnHalfW = floatingBtn ? floatingBtn.offsetWidth / 2 : 0;
let btnHalfH = floatingBtn ? floatingBtn.offsetHeight / 2 : 0;
window.addEventListener('resize', () => {
if (section) sectionRect = section.getBoundingClientRect();
if (floatingBtn) {
btnHalfW = floatingBtn.offsetWidth / 2;
btnHalfH = floatingBtn.offsetHeight / 2;
}
}, { passive: true });
window.addEventListener('scroll', () => {
if (section) sectionRect = section.getBoundingClientRect();
}, { passive: true });
if (section) {
section.addEventListener('mousemove', e => {
targetX = e.clientX - sectionRect.left;
targetY = e.clientY - sectionRect.top;
if (!isInside) {
isInside = true;
if (floatingBtn) floatingBtn.classList.add('visible');
}
});
section.addEventListener('mouseleave', () => {
isInside = false;
if (floatingBtn) floatingBtn.classList.remove('visible');
});
}
function animateButton() {
currentX += (targetX - currentX) * 0.15;
currentY += (targetY - currentY) * 0.15;
if (floatingBtn) {
floatingBtn.style.transform = `translate(${currentX - btnHalfW}px, ${currentY - btnHalfH + 10}px)`;
}
requestAnimationFrame(animateButton);
}
animateButton();
}
if (window.matchMedia('(pointer: fine)').matches) {
const cursorCircle = document.querySelector('.cursor-circle');
let targetX2 = 0, targetY2 = 0;
let lastBubbleX = 0, lastBubbleY = 0, lastBubbleTime = 0;
const BUBBLE_GAP = 80, BUBBLE_INTERVAL = 100;
let rafPending = false;
document.addEventListener('mousemove', e => {
const x = e.clientX, y = e.clientY;
targetX2 = x;
targetY2 = y;
const dx = x - lastBubbleX, dy = y - lastBubbleY;
const dist = Math.sqrt(dx * dx + dy * dy);
const now = performance.now();
if (dist > BUBBLE_GAP && now - lastBubbleTime > BUBBLE_INTERVAL) {
createBubble(x, y);
lastBubbleX = x; lastBubbleY = y; lastBubbleTime = now;
}
if (!rafPending) {
rafPending = true;
requestAnimationFrame(() => {
if (cursorCircle) cursorCircle.style.transform = `translate(${targetX2 - 40}px, ${targetY2 - 40}px)`;
rafPending = false;
});
}
}, { passive: true });
function createBubble(x, y) {
const bubble = document.createElement('div');
bubble.classList.add('bubble');
bubble.style.cssText = `left:${x}px;top:${y}px`;
document.body.appendChild(bubble);
setTimeout(() => bubble.remove(), 900);
}
}
});
